#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 505;
const int M = 2e5+5;
const int INF = 0x3f3f3f3f;
int m,n,St,Ed,Sum,h[N];
int tot=1,head[M],to[M],nxt[M];
int wei[M],dis[M];queue<int> q;
bool vis[N],r[N][N],use[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Add_edge(int x,int y,int z){
    ++tot,to[tot]=y,wei[tot]=z;
    nxt[tot]=head[x],head[x]=tot;
    ++tot,to[tot]=x,wei[tot]=0;
    nxt[tot]=head[y],head[y]=tot;return;
}
bool BFS_Canit(){
    for(int i=1;i<=Ed;i++)dis[i]=0;
    while(!q.empty())q.pop();
    dis[St]=1,q.push(St);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int i=head[u];i;i=nxt[i]){
            int v=to[i],w=wei[i];
            if(!w||dis[v])continue;
            dis[v]=dis[u]+1;
            if(v==Ed)return 1;q.push(v);
        }
    }return 0;
}
int DFS_Cntflow(int u,int flow){
    if(u==Ed)return flow;int now=flow;
    for(int i=head[u];i;i=nxt[i]){
        if(now<=0)break;
        int v=to[i],w=wei[i];
        if(!w||dis[v]!=dis[u]+1)continue;
        int tmp=DFS_Cntflow(v,min(now,w));
        if(!tmp)dis[v]=0;
        else wei[i]-=tmp,wei[i^1]+=tmp,now-=tmp;
    }return flow-now;
}
int Sol_Dinic(){
    int res=0,flow=0;
    while(BFS_Canit())
        while(flow=DFS_Cntflow(St,INF))res+=flow;
    return res;
}
int main(){
    m=read(),n=read();
    St=m+n+1,Ed=St+1;
    for(int i=1;i<=m;i++){
        h[i]=read(),Sum+=h[i];
        Add_edge(St,i,h[i]);
        for(int j=1;j<=n;j++)Add_edge(i,j+m,1);
    }for(int i=1,x;i<=n;i++)
        x=read(),Add_edge(i+m,Ed,x);
    if(Sol_Dinic()==Sum)cout<<"1\n";
    else{cout<<"0\n";return 0;}
    for(int x=1;x<=m;x++)
        for(int i=head[x];i;i=nxt[i])
            if(to[i]>m&&to[i]<St&&!wei[i])
                r[x][to[i]-m]=1;
    for(int i=1;i<=m;cout<<"\n"&&i++){
        for(int j=1;j<=n;j++)use[j]=0;
        for(int j=1;j<=h[i];j++)for(int k=1;k<=n;k++)
            if(!use[k]&&r[i][k]){use[k]=1;cout<<k<<" ";break;}
    }
    return 0;
}
